package net.minecraft.network.play.client;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayServer;
import net.minecraft.util.BlockPos;
import net.minecraft.util.ChatComponentText;
import net.minecraft.util.IChatComponent;
import java.io.IOException;

public class C12PacketUpdateSign implements Packet<INetHandlerPlayServer> {
    private BlockPos pos;
    private IChatComponent[] lines;

    public C12PacketUpdateSign() {}
    public C12PacketUpdateSign(BlockPos posIn, String[] linesIn) {
        this.pos = posIn;
        this.lines = new IChatComponent[4];
        for (int i = 0; i < 4; i++) {
            this.lines[i] = new ChatComponentText(linesIn[i]);
        }
    }
    public C12PacketUpdateSign(BlockPos posIn, IChatComponent[] linesIn) {
        this.pos = posIn;
        this.lines = new IChatComponent[] {linesIn[0], linesIn[1], linesIn[2], linesIn[3]};
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.pos = buf.readBlockPos();
        this.lines = new IChatComponent[4];
        for (int i = 0; i < 4; i++) {
            this.lines[i] = buf.readChatComponent();
        }
    }

    public void writePacketData(PacketBuffer buf) throws IOException {
        buf.writeBlockPos(this.pos);
        for (int i = 0; i < 4; i++) {
            buf.writeChatComponent(this.lines[i]);
        }
    }

    public void processPacket(INetHandlerPlayServer handler) {
        handler.processUpdateSign(this);
    }

    public BlockPos getPosition() { return this.pos; }
    public IChatComponent[] getLines() { return this.lines; }
}

